// Configuration:
@Configuration
class ChatMemoryConfig {
    @Bean
    ChatMemoryProvider razorpayChatMemoryProvider() {
        // One MessageWindowChatMemory per unique sessionId:
        return memoryId -> MessageWindowChatMemory.builder()
            .maxMessages(10)  // remember last 10 messages (5 turns)
            .id(memoryId)
            .build();
    }

    // HOW IT WORKS:
    // merchant: 'My payment gateway ID is MRC-001'
    // AI: 'Got it. What can I help you with?'
    // merchant: 'Why are my webhooks failing?'
    // AI: 'For gateway MRC-001, I see...' (remembers MRC-001!)
    // maxMessages=10: oldest messages dropped when limit reached (sliding window)
}

