// Tool provider: methods callable by the AI
@Component
class PaymentToolsService {
    // Simulated payment DB:
    private static final Map<String, String> STATUSES = Map.of(
        "PAY-001", "CAPTURED",
        "PAY-002", "FAILED",
        "PAY-003", "REFUND_INITIATED"
    );

    @Tool("Get the current status of a Razorpay payment by its payment ID")
    public String getPaymentStatus(String paymentId) {
        return STATUSES.getOrDefault(paymentId, "PAYMENT_NOT_FOUND");
    }

    @Tool("Get the estimated arrival time for a refund by payment ID")
    public String getRefundETA(String paymentId) {
        String status = STATUSES.get(paymentId);
        if ("REFUND_INITIATED".equals(status)) return "3-5 business days (initiated 2 days ago)";
        if ("CAPTURED".equals(status)) return "No refund initiated for this payment";
        return "Payment not found";
    }
}

// AiService interface:
interface RazorpayPaymentAI {
    @SystemMessage("""
        You are Razorpay's payment status assistant.
        When asked about payment status or refunds, use your tools to get real data.
        Never make up payment statuses — always use the tools.
        """)
    String help(@UserMessage String merchantQuery);
}

@SpringBootTest
class ToolsTest {
