    @Test void tools_defined() throws Exception {
        Method statusMethod = PaymentToolsService.class.getMethod("getPaymentStatus", String.class);
        Tool statusTool = statusMethod.getAnnotation(Tool.class);
        assertNotNull(statusTool);
        assertTrue(statusTool.value().contains("payment"));

        Method refundMethod = PaymentToolsService.class.getMethod("getRefundETA", String.class);
