// TokenStream: LangChain4j's streaming return type:
@AiService
interface StreamingBankAI {
    @SystemMessage("You are HDFC Bank's streaming chat assistant.")
    TokenStream streamAnswer(@UserMessage String question);
}

// Convert TokenStream to Spring WebFlux Flux<String> for SSE:
@RestController
@RequestMapping("/api/ai")
class StreamingChatController {
    private final StreamingBankAI ai;
    StreamingChatController(StreamingBankAI a) { ai = a; }

    @GetMapping(value = "/stream", produces = MediaType.TEXT_EVENT_STREAM_VALUE)
    public Flux<String> stream(@RequestParam String question) {
        return Flux.create(sink -> {
            ai.streamAnswer(question)
                .onNext(token -> sink.next(token))         // emit each token
                .onComplete(r -> sink.complete())          // close stream when done
                .onError(err -> {
                    sink.next("[ERROR]: " + err.getMessage());
                    sink.complete();
                })
                .start();
        });
    }
}

@SpringBootTest
class StreamingTest {
    @Test void interface_hasTokenStreamReturn() throws Exception {
        Method m = StreamingBankAI.class.getMethod("streamAnswer", String.class);
        assertEquals(TokenStream.class, m.getReturnType());
    }
}

