// Structured output record:
public record TicketRoute(
    String team,                     // PAYMENTS | FRAUD | TECHNICAL | BILLING
    int urgency,                     // 1-5
    String summary,                  // one sentence summary
    int estimatedResolutionHours     // 1, 4, 8, 24, 48
) {}

// Interface that returns a typed record (LangChain4j handles JSON parsing):
@AiService
interface RouteTicketAI {
    @SystemMessage("""
        You are Razorpay's ticket routing AI.
        Route support tickets to the right team with urgency and resolution time.
        team: PAYMENTS (payment issues), FRAUD (suspicious activity),
              TECHNICAL (API/integration), BILLING (invoices/fees).
        urgency: 5=critical, 4=high, 3=medium, 2=low, 1=informational.
        estimatedResolutionHours: typical for the category.
        """)
    // LangChain4j automatically generates JSON schema from return type:
    TicketRoute route(@UserMessage String ticketText);
}

// HOW STRUCTURED OUTPUT WORKS IN LANGCHAIN4J:
// Method return type: TicketRoute record
// LangChain4j: generates JSON schema → includes in prompt
// AI returns: valid JSON matching TicketRoute fields
// LangChain4j: deserializes JSON → TicketRoute record
// Same as Spring AI's BeanOutputConverter, but automatic!

@SpringBootTest
class StructuredOutputTest {
    @Test void method_returnType_isTicketRoute() throws Exception {
        Method m = RouteTicketAI.class.getMethod("route", String.class);
        assertEquals(TicketRoute.class, m.getReturnType());
    }
    @Test void ticketRoute_record_hasFields() {
        // Verify record fields:
        TicketRoute route = new TicketRoute("FRAUD", 5, "Unauthorized transaction", 1);
        assertEquals("FRAUD", route.team());
        assertEquals(5, route.urgency());
        assertTrue(route.estimatedResolutionHours() > 0);
    }
}

