// === SPRING AI VERSION ===
@Service
class SpringAiTicketClassifier {
    private final ChatClient client;
    private final BeanOutputConverter<TicketClassifResult> conv;
    SpringAiTicketClassifier(ChatClient.Builder b){
        conv=new BeanOutputConverter<>(TicketClassifResult.class);
        client=b.defaultSystem("Classify HDFC support tickets. department: LOAN|CARD|ACCOUNT|OTHER. priority: 1-5. needsHuman: true if priority>=4.").build();
