import dev.langchain4j.service.*;
import dev.langchain4j.service.spring.AiService;
import dev.langchain4j.memory.chat.*;
import org.springframework.stereotype.*;
import org.springframework.context.annotation.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.concurrent.ConcurrentHashMap;
import java.time.Instant;
import java.time.Duration;
import java.util.Map;

@Service
class TenantMemoryManager {
    private final Map<String, ChatMemory> memories = new ConcurrentHashMap<>();
    private final Map<String, Instant> lastAccess = new ConcurrentHashMap<>();
    private static final Duration EXPIRY = Duration.ofMinutes(30);

    // Composite key: merchantId:conversationId
    public ChatMemory getMemory(String merchantId, String conversationId) {
        String key = merchantId + ":" + conversationId;
        lastAccess.put(key, Instant.now());
        return memories.computeIfAbsent(key,
            k -> MessageWindowChatMemory.builder().maxMessages(10).id(k).build());
    }

    public boolean isExpired(String merchantId, String conversationId) {
        String key = merchantId + ":" + conversationId;
        Instant last = lastAccess.get(key);
        if (last == null) return true;
        return Instant.now().isAfter(last.plus(EXPIRY));
    }

    public void clearExpired() {
        Instant cutoff = Instant.now().minus(EXPIRY);
        lastAccess.entrySet().removeIf(e -> e.getValue().isBefore(cutoff));
        memories.keySet().removeIf(k -> !lastAccess.containsKey(k));
    }

    public String buildKey(String merchantId, String conversationId) {
        return merchantId + ":" + conversationId;
    }
}

@SpringBootTest
class TenantIsolationTest {
    @Autowired TenantMemoryManager manager;

    @Test void different_merchants_isolated() {
        var memA = manager.getMemory("MRC-001", "conv-1");
        var memB = manager.getMemory("MRC-002", "conv-1");
        assertNotSame(memA, memB); // different merchants, same conv ID = different memory
    }
    @Test void same_merchant_different_conv_isolated() {
        var conv1 = manager.getMemory("MRC-001", "conv-1");
        var conv2 = manager.getMemory("MRC-001", "conv-2");
        assertNotSame(conv1, conv2); // same merchant, different conversations
    }
    @Test void key_format_is_composite() {
        String key = manager.buildKey("MRC-001", "abc-123");
        assertEquals("MRC-001:abc-123", key);
        assertTrue(key.contains(":"), "Key must use ':' separator for merchantId:conversationId");
    }
}

import dev.langchain4j.agent.tool.Tool;
import dev.langchain4j.service.*;
import dev.langchain4j.service.spring.AiService;
import dev.langchain4j.memory.chat.*;
import org.springframework.stereotype.*;
import org.springframework.context.annotation.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.lang.reflect.Method;

@Component
class SynthL4jTools {
    @Tool("Get payment status") public String payStatus(String id){return "CAPTURED";}
    @Tool("Get merchant tier") public String merchantTier(String id){return "PREMIUM";}
}

@AiService
interface SynthL4jAI {
    @SystemMessage("You are HDFC Bank AI. Use tools for real data.")
    String help(@UserMessage String msg, @MemoryId String sessionId);
}

@Configuration
class SynthL4jConfig {
    @Bean ChatMemoryProvider synthMemory(){return sid->MessageWindowChatMemory.builder().maxMessages(8).id(sid).build();}
}

@Service
class SynthKeyBuilder {
    String build(String merchantId, String conversationId){return merchantId+":"+conversationId;}
    boolean isValid(String key){return key!=null&&key.contains(":")&&key.split(":").length==2;}
}

@SpringBootTest
class M26T4SynthesisTest {
    @Autowired SynthL4jTools tools;
    @Autowired ChatMemoryProvider synthMemory;
    @Autowired SynthKeyBuilder keyBuilder;

    @Test void interface_hasAnnotations() throws Exception {
        Method m=SynthL4jAI.class.getMethod("help",String.class,String.class);
        assertNotNull(m.getAnnotation(SystemMessage.class));
    }
    @Test void tools_functional(){
        assertEquals("CAPTURED",tools.payStatus("P1"));
        assertEquals("PREMIUM",tools.merchantTier("M1"));
    }
    @Test void memory_isolated(){
        assertNotSame(synthMemory.get("session-A"),synthMemory.get("session-B"));
    }
    @Test void key_composite(){
        String key=keyBuilder.build("MRC-001","conv-1");
        assertEquals("MRC-001:conv-1",key);
        assertTrue(keyBuilder.isValid(key));
    }
}
